import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { invariantMissingProofRule } from "./invariant-missing-proof.rule.js";

const ENTITY = `
  namespace Products.MyProduct.Entities.Task {
    @entity
    model Task { id: string; }
  }
  using Products.MyProduct.Entities.Task;
`;

const FEATURE_WITH_INV = `
  @feature
  namespace Products.MyProduct.Features.Lifecycle {
    @invariant(#{
      predicate: "A {@Task} has an id.",
      why: "Reason.",
    })
    op task_has_id(): void;
  }
`;

describe("invariant-missing-proof rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, invariantMissingProofRule, "@a10n/blueprint-typespec");
  });

  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T005.T005_01
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_missing_proof:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.inv_has_proof:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_operation_reachability_2:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.inv_has_proof:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_missing_proof
    it("invariant proven by a projecting-op-kind op (@tool in Agent)", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @tool(#{ sequential: false })
            @projects(Products.MyProduct.Features.Lifecycle.task_has_id)
            op do_task(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T005.T005_02
    it("invariant proven by a @signal with @projects", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "s",
                method: SignalMethod.Deterministic,
                criteria: "criteria",
                examples: #[],
              })
              @projects(Products.MyProduct.Features.Lifecycle.task_has_id)
              op E001_01(): boolean;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T005.T005_08
    it("invariant proven by an http_op (op in an Http ns inside a @component)", async () => {
      // http_op is classified by namespace path (Components.%.Http.%), not by the
      // @typespec/http verb decorator — those decorators don't surface to the linter.
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            namespace Http {
              @projects(Products.MyProduct.Features.Lifecycle.task_has_id)
              op get_task(): void;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T005.T005_03
    it("@projects listing two invariants covers both", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{ predicate: "A {@Task} has an id.", why: "Reason." })
            op task_has_id(): void;
            @invariant(#{ predicate: "A {@Task.id} is non-empty.", why: "Reason." })
            op id_nonempty(): void;
          }
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @tool(#{ sequential: false })
            @projects(
              Products.MyProduct.Features.Lifecycle.task_has_id,
              Products.MyProduct.Features.Lifecycle.id_nonempty
            )
            op do_task(): void;
          }
        `)
        .toBeValid();
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T005.T005_04
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_missing_proof:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.inv_has_proof:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_missing_proof
    it("invariant with no proof at all", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/invariant-missing-proof",
          message: /task_has_id/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T005.T005_06
    it("multiple invariants — only the unproven one fires", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{ predicate: "A {@Task} has an id.", why: "Reason." })
            op task_has_id(): void;
            @invariant(#{ predicate: "A {@Task.id} is non-empty.", why: "Reason." })
            op id_nonempty(): void;
          }
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @tool(#{ sequential: false })
            @projects(Products.MyProduct.Features.Lifecycle.task_has_id)
            op do_task(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/invariant-missing-proof",
          message: /id_nonempty/,
        });
    });
  });
});
